PRAGMA foreign_keys = ON;
BEGIN TRANSACTION;

CREATE TABLE IF NOT EXISTS manufacturers (id TEXT PRIMARY KEY, name TEXT, slug TEXT, notes TEXT, created_at TEXT);

CREATE TABLE IF NOT EXISTS vehicles ("id" TEXT, "slug" TEXT, "english_name" TEXT, "japanese_name" TEXT, "internal_name" TEXT, "manufacturer_id" TEXT, "vehicle_type_key" TEXT, "vehicle_class_key" TEXT, "vehicle_subclass" TEXT, "seat_capacity" TEXT, "drivetrain" TEXT, "engine_position" TEXT, "is_hsw" TEXT, "is_bennys" TEXT, "is_weaponized" TEXT, "is_armored" TEXT, "is_electric" TEXT, "is_convertible" TEXT, "purchase_price" TEXT, "trade_price" TEXT, "currency" TEXT, "purchase_site" TEXT, "storage_location" TEXT, "is_limited_stock" TEXT, "is_removed_from_store" TEXT, "game_model_hash" TEXT, "handling_profile_id" TEXT, "release_dlc" TEXT, "release_date" TEXT, "game_build_added" TEXT, "notes" TEXT, "default_color_set_id" TEXT, "created_at" TEXT, "updated_at" TEXT);

